var e=[{id:`L2_1`,type:`dialog`,speaker:`CATHY_CIVIL_WEDDING_NULL`,text:{KOREA:`역시 함께 작업한다는 건 즐겁네요. 사장님께서 이렇게 적극적으로 협조해주실 줄은 몰랐어요.`,JPN:`やっぱり、一緒に仕事をするのは楽しいですね。社長がこんなに積極的に協力してくださるとは思いませんでした。`,ENG:`It sure is fun working with you. I never knew you'd cooperate so actively.`,TWN:`一起工作果然很開心啊，沒想到老闆你會這麼積極地配合。`},stage:{bg:`CHURCH`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CATHY_CIVIL_WEDDING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CATHY_CIVIL_WEDDING_NULL`,text:{KOREA:`연기를 위해서 조금 과하게 몰입하긴 했지만, 사장님이 안 말려주셨으면 정말 실례를 저지를 뻔했지 뭐에요? ......후훗.`,JPN:`お芝居のためにちょっと感情移入しすぎちゃって、社長が止めてくださらなかったら、本当に失礼なことをしちゃうところでしたよ。うふふ……`,ENG:`Although I guess I went a bit overboard with the acting. If you hadn't stopped me, I might have crossed a line or two, you know? Hah hah.`,TWN:`雖然我為了演技，有些太過投入了，但要是老闆沒有阻止我的話，我可能就會做出什麼失禮的事情了呢……呵呵。`},stage:{bg:`CHURCH`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CATHY_CIVIL_WEDDING_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};